/* wif-das-batch-interface-sql-oracle.xml - insertClassificationPlanWave - 분류계획 WAVE INSERT SQL */
INSERT INTO TWIF_DAS_CLASSIFPLAN_WA (
	WASEQ
	,CTKEY
	,OWKEY
	,WAHDKEY
	,WAHDDAY
	,DASEQTYPE
	,WKDATE
	,WASNDEMP
	,IFCD
	,WIFIFID
	,IFID
	,IFREQDT
	,IFTYPE
	,IFSRCMODULE
	,IFTGTMODULE
	,IFSTATUS
	,IFERRCD
	,IFERRMSG
	,IFPRCSDATE
	,ORD
	,INSERTURKEY
	,INSERTDATE
	,UPDATEURKEY
	,UPDATEDATE
)
VALUES
(
	#{waSeq}
	,#{ctKey}
	,#{owKey}
	,#{waHdKey}
	,#{waHdDay}
	,#{dasEqType}
	,#{wkDate}
	,#{waSndEmp}
	,#{ifCd}
	,#{wifIfId}
	,#{ifId}
	,#{ifReqDt}
	,#{ifType}
	,#{ifSrcModule}
	,#{ifTgtModule}
	,#{ifStatus}
	,#{ifErrCd}
	,#{ifErrMsg}
	,#{ifPrcsDate}
	,#{ord}
	,#{surkey}
	,#{sysdate}
	,#{surkey}
	,#{sysdate}
)

