/* wif-das-batch-interface-sql-oracle.xml - updateClassificationPlanWaveResult - DAS 분류계획 송신 실적 UPDATE SQL */
UPDATE TWIF_DAS_CLASSIFPLAN_WA
   SET IFSTATUS		= #{ifStatus}
	   ,IFERRCD		= #{ifErrCd}
	   ,IFERRMSG	= #{ifErrMsg}
	   ,IFPRCSDATE	= #{sysdate}
	   ,UPDATEDATE  = #{sysdate}
	   ,UPDATEURKEY = #{surkey}
 WHERE WASEQ 		= #{waSeq}

/* wif-das-interface-sql-oracle.xml - updateWmsClassificationPlanWaveResponse - DAS 분류계획 송신 실적 WMS UPDATE SQL */
UPDATE TWORK_INFO_WA_HD
SET WAWKSTATUSCD = #{waWkStatusCd}
,UPDATEDATE 	= #{sysdate}
,UPDATEURKEY = #{surkey}
WHERE CTKEY 		= #{ctKey}
AND OWKEY 		= #{owKey}
AND WAHDKEY 		= #{waHdKey}

